+/**
+ * Webhook notification adapter.
+ *
+ * Implements NotificationAdapter for the 'webhook' channel. Formats the
+ * notification payload as JSON and POSTs it to the recipient URL.
+ *
+ * ## Usage
+ * ```ts
+ * const webhookAdapter = new WebhookAdapter(eventBus);
+ * notificationService.registerAdapter(webhookAdapter);
+ * ```
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { NotificationSendEvent } from '../events/event-types.js';
+import type {
+  NotificationChannel,
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+import type { NotificationAdapter } from './notification.adapter.js';
+
+// ---------------------------------------------------------------------------
+// Webhook transport abstraction
+// ---------------------------------------------------------------------------
+
+/** The JSON body sent to the webhook URL. */
+export interface WebhookBody {
+  event: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  priority: string;
+  metadata?: Record<string, string>;
+  timestamp: string;
+}
+
+/**
+ * Pluggable transport that performs the actual HTTP POST.
+ * Swap in a real HTTP client for production.
+ */
+export interface WebhookTransport {
+  post(url: string, body: WebhookBody): Promise<{ statusCode: number }>;
+}
+
+/**
+ * Default in-memory transport that records posted webhooks.
+ * Used in development / testing.
+ */
+export class InMemoryWebhookTransport implements WebhookTransport {
+  private sent: Array<{ url: string; body: WebhookBody }> = [];
+
+  async post(url: string, body: WebhookBody): Promise<{ statusCode: number }> {
+    this.sent.push({ url, body });
+    return { statusCode: 200 };
+  }
+
+  getSentWebhooks(): Array<{ url: string; body: WebhookBody }> {
+    return [...this.sent];
+  }
+
+  clear(): void {
+    this.sent = [];
+  }
+}
+
+// ---------------------------------------------------------------------------
+// Payload formatting
+// ---------------------------------------------------------------------------
+
+/**
+ * Format a notification payload into a webhook JSON body.
+ */
+export function formatWebhookPayload(payload: NotificationPayload): WebhookBody {
+  return {
+    event: payload.notificationType,
+    recipient: payload.recipient,
+    subject: payload.subject,
+    body: payload.body,
+    priority: payload.priority ?? 'normal',
+    metadata: payload.metadata,
+    timestamp: new Date().toISOString(),
+  };
+}
+
+// ---------------------------------------------------------------------------
+// URL validation
+// ---------------------------------------------------------------------------
+
+const URL_REGEX = /^https?:\/\/.+/;
+
+/**
+ * Validate a webhook URL.
+ * Returns the trimmed URL or null if invalid.
+ */
+export function validateWebhookUrl(url: string): string | null {
+  const trimmed = url.trim();
+  if (!URL_REGEX.test(trimmed)) {
+    return null;
+  }
+  return trimmed;
+}
+
+// ---------------------------------------------------------------------------
+// WebhookAdapter
+// ---------------------------------------------------------------------------
+
+export class WebhookAdapter implements NotificationAdapter {
+  readonly channel: NotificationChannel = 'webhook';
+  private logger = new Logger('WebhookAdapter');
+  private transport: WebhookTransport;
+
+  /** Sent payloads — exposed for testing. */
+  private sent: NotificationPayload[] = [];
+
+  constructor(private eventBus: EventBus, transport?: WebhookTransport) {
+    this.transport = transport ?? new InMemoryWebhookTransport();
+    this.registerHandler();
+  }
+
+  /**
+   * Subscribe to notification:send events and handle webhook-channel payloads.
+   */
+  private registerHandler(): void {
+    this.eventBus.on<NotificationSendEvent>('notification:send', async (event) => {
+      if (event.payload.channel === this.channel) {
+        await this.send(event.payload);
+      }
+    });
+  }
+
+  /**
+   * Deliver a webhook notification.
+   *
+   * 1. Validate the recipient URL.
+   * 2. Format the notification payload as JSON.
+   * 3. POST it via the configured transport.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    try {
+      // 1. URL validation
+      const url = validateWebhookUrl(payload.recipient);
+      if (!url) {
+        const error = `Invalid webhook URL: ${payload.recipient}`;
+        this.logger.error(error);
+        return { success: false, error };
+      }
+
+      // 2. Format payload
+      const body = formatWebhookPayload(payload);
+
+      // 3. POST via transport
+      const result = await this.transport.post(url, body);
+      this.logger.info(
+        `Webhook sent to ${url}: "${payload.subject}" [${result.statusCode}]`,
+      );
+
+      this.sent.push(payload);
+      return { success: true };
+    } catch (err: unknown) {
+      const message = err instanceof Error ? err.message : 'Unknown webhook delivery error';
+      this.logger.error(`Failed to send webhook to ${payload.recipient}: ${message}`);
+      return { success: false, error: message };
+    }
+  }
+
+  /**
+   * Get all payloads that were successfully sent (useful for testing).
+   */
+  getSentWebhooks(): NotificationPayload[] {
+    return [...this.sent];
+  }
+
+  /**
+   * Clear the sent webhooks list (useful for testing).
+   */
+  clearSentWebhooks(): void {
+    this.sent = [];
+  }
+
+  /**
+   * Get the underlying transport (useful for testing with InMemoryWebhookTransport).
+   */
+  getTransport(): WebhookTransport {
+    return this.transport;
+  }
+}

