  // -------------------------------------------------------------------------
  // send()
  // -------------------------------------------------------------------------

  describe('send', () => {
    const payload: NotificationPayload = {
      recipient: 'https://hooks.example.com/webhook',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      notificationType: 'order_confirmation',
      channel: 'webhook',
